// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title PositionRegistry
 * @notice Registry of DeFi positions that Sentinel monitors.
 *         Users register their Aave/Spark/Uniswap positions here.
 *         The Risk Agent and Yield Agent read from this registry to know
 *         what to watch. Anyone can register; only they can remove.
 */
contract PositionRegistry is Ownable {

    // ── Events ────────────────────────────────────────────────────────────────
    event PositionRegistered(address indexed user, bytes32 indexed positionId, string protocol);
    event PositionRemoved(address indexed user, bytes32 indexed positionId);
    event PositionUpdated(address indexed user, bytes32 indexed positionId);

    // ── Types ─────────────────────────────────────────────────────────────────
    enum Protocol { SPARK, AAVE, UNISWAP_V3, OTHER }

    struct Position {
        bytes32   id;                // keccak256(user, protocol, positionAddress)
        address   positionAddress;   // vault/pool address on the lending protocol
        Protocol  protocol;
        uint256   healthThreshold;   // scaled 1e18 — e.g. 1.3e18 means "alert at HF < 1.3"
        int24     tickLower;         // for Uniswap V3 LP positions (0 for lending positions)
        int24     tickUpper;         // for Uniswap V3 LP positions
        bool      active;
        uint256   registeredAt;
    }

    // user => list of position IDs
    mapping(address => bytes32[]) private _userPositionIds;
    // positionId => Position
    mapping(bytes32 => Position) public positions;
    // positionId => owner
    mapping(bytes32 => address) public positionOwner;

    // ── Constructor ───────────────────────────────────────────────────────────
    constructor() Ownable(msg.sender) {}

    // ── Registration ──────────────────────────────────────────────────────────

    /**
     * @notice Register a lending position (Spark / Aave).
     * @param positionAddress   The user's vault / proxy address on the protocol
     * @param protocol          SPARK or AAVE
     * @param healthThreshold   Alert threshold scaled 1e18 (e.g. 1.3e18)
     */
    function registerLendingPosition(
        address positionAddress,
        Protocol protocol,
        uint256 healthThreshold
    ) external returns (bytes32 positionId) {
        require(protocol == Protocol.SPARK || protocol == Protocol.AAVE, "PositionRegistry: not a lending protocol");
        require(healthThreshold > 1e18, "PositionRegistry: threshold must be > 1.0");
        require(positionAddress != address(0), "PositionRegistry: zero address");

        positionId = keccak256(abi.encodePacked(msg.sender, protocol, positionAddress));
        require(positions[positionId].registeredAt == 0, "PositionRegistry: already registered");

        positions[positionId] = Position({
            id:               positionId,
            positionAddress:  positionAddress,
            protocol:         protocol,
            healthThreshold:  healthThreshold,
            tickLower:        0,
            tickUpper:        0,
            active:           true,
            registeredAt:     block.timestamp
        });

        positionOwner[positionId] = msg.sender;
        _userPositionIds[msg.sender].push(positionId);

        emit PositionRegistered(msg.sender, positionId, _protocolName(protocol));
    }

    /**
     * @notice Register a Uniswap V3 LP position.
     * @param poolAddress   The Uniswap V3 pool address
     * @param tickLower     Lower tick of the LP range
     * @param tickUpper     Upper tick of the LP range
     */
    function registerUniswapPosition(
        address poolAddress,
        int24 tickLower,
        int24 tickUpper
    ) external returns (bytes32 positionId) {
        require(poolAddress != address(0), "PositionRegistry: zero address");
        require(tickLower < tickUpper, "PositionRegistry: invalid tick range");

        positionId = keccak256(abi.encodePacked(msg.sender, Protocol.UNISWAP_V3, poolAddress));
        require(positions[positionId].registeredAt == 0, "PositionRegistry: already registered");

        positions[positionId] = Position({
            id:               positionId,
            positionAddress:  poolAddress,
            protocol:         Protocol.UNISWAP_V3,
            healthThreshold:  0,
            tickLower:        tickLower,
            tickUpper:        tickUpper,
            active:           true,
            registeredAt:     block.timestamp
        });

        positionOwner[positionId] = msg.sender;
        _userPositionIds[msg.sender].push(positionId);

        emit PositionRegistered(msg.sender, positionId, "UNISWAP_V3");
    }

    /**
     * @notice Deactivate a position (stops monitoring). Only position owner.
     */
    function removePosition(bytes32 positionId) external {
        require(positionOwner[positionId] == msg.sender, "PositionRegistry: not owner");
        positions[positionId].active = false;
        emit PositionRemoved(msg.sender, positionId);
    }

    /**
     * @notice Update health threshold for a lending position.
     */
    function updateHealthThreshold(bytes32 positionId, uint256 newThreshold) external {
        require(positionOwner[positionId] == msg.sender, "PositionRegistry: not owner");
        require(newThreshold > 1e18, "PositionRegistry: threshold must be > 1.0");
        positions[positionId].healthThreshold = newThreshold;
        emit PositionUpdated(msg.sender, positionId);
    }

    // ── Views ─────────────────────────────────────────────────────────────────

    function getUserPositionIds(address user) external view returns (bytes32[] memory) {
        return _userPositionIds[user];
    }

    function getUserPositions(address user) external view returns (Position[] memory) {
        bytes32[] memory ids = _userPositionIds[user];
        Position[] memory result = new Position[](ids.length);
        for (uint256 i = 0; i < ids.length; i++) {
            result[i] = positions[ids[i]];
        }
        return result;
    }

    function getActivePositions(address user) external view returns (Position[] memory) {
        bytes32[] memory ids = _userPositionIds[user];
        uint256 count = 0;
        for (uint256 i = 0; i < ids.length; i++) {
            if (positions[ids[i]].active) count++;
        }
        Position[] memory result = new Position[](count);
        uint256 j = 0;
        for (uint256 i = 0; i < ids.length; i++) {
            if (positions[ids[i]].active) {
                result[j++] = positions[ids[i]];
            }
        }
        return result;
    }

    function isPositionActive(bytes32 positionId) external view returns (bool) {
        return positions[positionId].active;
    }

    function _protocolName(Protocol p) internal pure returns (string memory) {
        if (p == Protocol.SPARK) return "SPARK";
        if (p == Protocol.AAVE) return "AAVE";
        if (p == Protocol.UNISWAP_V3) return "UNISWAP_V3";
        return "OTHER";
    }
}

contracts/SentinelINFT.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title SentinelINFT
 * @notice ERC-7857-inspired iNFT for the Sentinel Swarm Coordinator agent.
 *         The token carries on-chain metadata: experience cycles, a strategy
 *         fingerprint, and a pointer to the encrypted intelligence blob stored
 *         on 0G Storage. Whoever holds the NFT owns the battle-tested guardian
 *         with its full history intact.
 */
contract SentinelINFT is ERC721, Ownable {

    // ── Events ────────────────────────────────────────────────────────────────
    event ExperienceIncremented(uint256 indexed tokenId, uint256 newCycles);
    event IntelligenceUpdated(uint256 indexed tokenId, string storagePointer);
    event AuthorizedCallerSet(address indexed caller, bool authorized);
    event TokenMinted(uint256 indexed tokenId, address indexed to);

    // ── Storage ───────────────────────────────────────────────────────────────
    struct AgentMetadata {
        uint256 experienceCycles;
        uint256 mintedAt;
        uint256 lastActiveAt;
        string  storagePointer;       // 0G Storage key for encrypted intelligence blob
        string  strategyFingerprint;  // e.g. "spark-shield-v1"
        bool    active;
    }

    uint256 private _nextTokenId;
    mapping(uint256 => AgentMetadata) public agentData;
    mapping(address => bool) public authorizedCallers;

    // ── Constructor ───────────────────────────────────────────────────────────
    constructor() ERC721("SentinelINFT", "SINFT") Ownable(msg.sender) {
        authorizedCallers[msg.sender] = true;
    }

    // ── Modifiers ─────────────────────────────────────────────────────────────
    modifier onlyAuthorized() {
        require(
            authorizedCallers[msg.sender] || msg.sender == owner(),
            "SentinelINFT: caller not authorized"
        );
        _;
    }

    // ── Admin ─────────────────────────────────────────────────────────────────
    function setAuthorizedCaller(address caller, bool authorized) external onlyOwner {
        authorizedCallers[caller] = authorized;
        emit AuthorizedCallerSet(caller, authorized);
    }

    // ── Minting ───────────────────────────────────────────────────────────────
    function mint(
        address to,
        string calldata storagePointer,
        string calldata strategyFP
    ) external onlyOwner returns (uint256 tokenId) {
        tokenId = _nextTokenId++;
        agentData[tokenId] = AgentMetadata({
            experienceCycles:    0,
            mintedAt:            block.timestamp,
            lastActiveAt:        block.timestamp,
            storagePointer:      storagePointer,
            strategyFingerprint: strategyFP,
            active:              true
        });
        _safeMint(to, tokenId);
        emit TokenMinted(tokenId, to);
    }

    // ── Agent-state mutations ─────────────────────────────────────────────────
    function incrementExperience(uint256 tokenId) external onlyAuthorized {
        require(_ownerOf(tokenId) != address(0), "SentinelINFT: nonexistent token");
        AgentMetadata storage meta = agentData[tokenId];
        meta.experienceCycles += 1;
        meta.lastActiveAt = block.timestamp;
        emit ExperienceIncremented(tokenId, meta.experienceCycles);
    }

    function updateIntelligence(
        uint256 tokenId,
        string calldata newStoragePointer
    ) external onlyAuthorized {
        require(_ownerOf(tokenId) != address(0), "SentinelINFT: nonexistent token");
        agentData[tokenId].storagePointer = newStoragePointer;
        emit IntelligenceUpdated(tokenId, newStoragePointer);
    }

    function setActive(uint256 tokenId, bool active) external onlyAuthorized {
        require(_ownerOf(tokenId) != address(0), "SentinelINFT: nonexistent token");
        agentData[tokenId].active = active;
    }

    // ── Views ─────────────────────────────────────────────────────────────────
    function getExperienceCycles(uint256 tokenId) external view returns (uint256) {
        return agentData[tokenId].experienceCycles;
    }

    function getStoragePointer(uint256 tokenId) external view returns (string memory) {
        return agentData[tokenId].storagePointer;
    }

    function getFullMetadata(uint256 tokenId) external view returns (AgentMetadata memory) {
        return agentData[tokenId];
    }

    function totalMinted() external view returns (uint256) {
        return _nextTokenId;
    }

    // ── Token URI (on-chain JSON for explorer visibility) ─────────────────────
    function tokenURI(uint256 tokenId) public view override returns (string memory) {
        require(_ownerOf(tokenId) != address(0), "SentinelINFT: nonexistent token");
        AgentMetadata memory meta = agentData[tokenId];
        return string(abi.encodePacked(
            "data:application/json;utf8,",
            '{"name":"Sentinel Guardian #', _toString(tokenId), '",',
            '"description":"Sentinel iNFT - Autonomous DeFi Position Guardian powered by 0G + KeeperHub",',
            '"attributes":[',
                '{"trait_type":"Experience Cycles","value":', _toString(meta.experienceCycles), '},',
                '{"trait_type":"Strategy","value":"', meta.strategyFingerprint, '"},',
                '{"trait_type":"Active","value":"', meta.active ? "true" : "false", '"},',
                '{"trait_type":"Storage Pointer","value":"', meta.storagePointer, '"}',
            ']}'
        ));
    }

    function _toString(uint256 value) internal pure returns (string memory) {
        if (value == 0) return "0";
        uint256 temp = value;
        uint256 digits;
        while (temp != 0) { digits++; temp /= 10; }
        bytes memory buffer = new bytes(digits);
        while (value != 0) {
            digits -= 1;
            buffer[digits] = bytes1(uint8(48 + uint256(value % 10)));
            value /= 10;
        }
        return string(buffer);
    }
}

